__CPROVER_requires(__CPROVER_is_fresh(ll_counts, ZOPFLI_NUM_LL * sizeof(*ll_counts)))
__CPROVER_requires(__CPROVER_is_fresh(d_counts, ZOPFLI_NUM_D * sizeof(*d_counts)))
